option.value:
body {
  background: #121214;
  color: #e8e8ea;
  font-family: -apple-system, BlinkMacSystemFont, sans-serif;
  line-height: 1.8;
  padding: 32px;
}

/* 標題 */
h1, h2, h3, h4, h5, h6 {
  color: #FCCE22;
  font-weight: 700;
}

/* list text */
ul,
ol {
  color: #E8E8EA;
  padding-left: 1.4em;
}

/* list item spacing */
li {
  margin: 0.35em 0;
}

/* bullet / number */
li::marker {
  color: #F1942B;
  font-weight: 700;
}

/* 連結 */
a {
  color: #F1942B;
  text-decoration: none;
}

a:hover {
  opacity: 0.8;
  text-decoration: underline;
}

/* 引述 */
blockquote {
  color: #F29428;
  border-left: 3px solid #F29428;
  padding-left: 16px;
  margin-left: 0;
  opacity: 0.95;
}

/* inline code */
code {
  background: #1B1B1F;
  color: #E8E8EA;
  padding: 2px 6px;
  border-radius: 6px;
  font-size: 0.94em;
  font-family: "JetBrains Mono", monospace;
  border: 1px solid #2A2A30;
}

/* code block */
pre {
  background: #16161A;
  border: 1px solid #2A2A30;
  border-radius: 14px;
  padding: 18px 20px;
  overflow-x: auto;
  margin: 20px 0;
  box-shadow:
    inset 0 1px 0 rgba(255,255,255,0.03),
    0 4px 20px rgba(0,0,0,0.25);
}

/* remove duplicated inline style */
pre code {
  background: transparent;
  color: #EAEAEA;
  padding: 0;
  border-radius: 0;
  font-size: 0.95em;
  line-height: 1.75;
}

/* syntax highlight */

/* keyword */
.token.keyword {
  color: #F6C177;
}

/* string */
.token.string {
  color: #A6D189;
}

/* function */
.token.function {
  color: #8CAAEE;
}

/* number */
.token.number {
  color: #E5C890;
}

/* comment */
.token.comment {
  color: #6C7086;
  font-style: italic;
}

/* operator */
.token.operator {
  color: #F1942B;
}

/* class / type */
.token.class-name,
.token.type {
  color: #EFBBCB;
}

/* property */
.token.property {
  color: #81C8BE;
}

/* 表格 */
table {
  border-collapse: collapse;
}

th {
  color: #FCCE22;
}

td {
  color: #e8e8ea;
}

th,
td {
  border: 1px solid #2a2a2f;
  padding: 10px 14px;
}

/* 分隔線 */
hr {
  border: none;
  border-top: 1px solid #2a2a2f;
  margin: 32px 0;
}
